+            .await
+    }
+
+    // ── Image Export ────────────────────────────────────────────
+
+    /// Export node(s) as images.
+    #[instrument(skip(self))]
+    pub async fn export_images(
+        &self,
+        file_key: &str,
+        ids: &str,
+        format: &str,
+        scale: Option<f64>,
